parameters.jsonBody:
={
  "model": "mistral",
  "stream": false,
  "messages": [
    {
      "role": "system",
      "content": "Analizá la solicitud de receta del paciente. Respondé SOLO con JSON válido, sin explicación:\n\n{\n  \"es_renovacion\": true o false,\n  \"medicamento\": \"nombre del medicamento o null\",\n  \"dosis\": \"dosis o null\",\n  \"frecuencia\": \"frecuencia o null\",\n  \"tipo\": \"renovacion\" o \"nueva\" o \"consulta\"\n}"
    },
    {
      "role": "user",
      "content": "Mensaje del paciente: {{ $('Extraer Datos Solicitud').first().json.message }}"
    }
  ]
}

parameters.jsCode:
const ollamaResponse = $input.first().json.message.content;

let recetaData;
try {
  recetaData = JSON.parse(ollamaResponse);
} catch (e) {
  const match = ollamaResponse.match(/\{[\s\S]*\}/);
  if (match) {
    try {
      recetaData = JSON.parse(match[0]);
    } catch (e2) {
      recetaData = { es_renovacion: false, medicamento: null, dosis: null, frecuencia: null, tipo: 'consulta' };
    }
  } else {
    recetaData = { es_renovacion: false, medicamento: null, dosis: null, frecuencia: null, tipo: 'consulta' };
  }
}

return [{
  json: {
    es_renovacion: recetaData.es_renovacion === true,
    medicamento: recetaData.medicamento || null,
    dosis: recetaData.dosis || null,
    frecuencia: recetaData.frecuencia || null,
    tipo: recetaData.tipo || 'consulta',
    phone: $('Extraer Datos Solicitud').first().json.phone,
    profileName: $('Extraer Datos Solicitud').first().json.profileName,
    fromNumber: $('Extraer Datos Solicitud').first().json.fromNumber,
    toNumber: $('Extraer Datos Solicitud').first().json.toNumber
  }
}];
